import{_ as t,o as a,c as i,a2 as s}from"./chunks/framework.DTa47_fH.js";const c=JSON.parse('{"title":"Generate TF Modules","description":"","frontmatter":{},"headers":[],"relativePath":"generate-tf.md","filePath":"generate-tf.md"}'),n={name:"generate-tf.md"};function r(o,e,l,d,p,h){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="generate-tf-modules" tabindex="-1">Generate TF Modules <a class="header-anchor" href="#generate-tf-modules" aria-label="Permalink to &quot;Generate TF Modules&quot;">​</a></h1><p>Generate TF Modules produces ready-to-apply Terraform modules from the assessment results. When the assessment finds that a control is not satisfied, SWAO can generate the Terraform code that would bring the environment into compliance -- turning findings into infrastructure as code in one step.</p><p>Access from the TUI main menu by pressing <strong>8</strong>.</p><hr><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>After an Application or Landing Zone assessment, SWAO maps each unsatisfied control to a curated library of Terraform modules. For each matching module, it generates:</p><ul><li>A configured <code>.tf</code> file with values pre-filled from the application context (app ID, cloud region, resource names, tags).</li><li>A <code>variables.tf</code> block for any values that must be supplied at apply time.</li><li>A <code>README.md</code> per module describing what it remediates and how to apply it.</li></ul><p>The output lands in <code>apps/&lt;id&gt;/wsp/tf/&lt;timestamp&gt;/</code> and is structured so it can be applied directly or imported into an existing Terraform root module.</p><hr><h2 id="supported-providers" tabindex="-1">Supported providers <a class="header-anchor" href="#supported-providers" aria-label="Permalink to &quot;Supported providers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Coverage</th></tr></thead><tbody><tr><td>AWS</td><td>IAM, S3, KMS, CloudTrail, Config, Security Hub, WAF, VPC flow logs</td></tr><tr><td>Azure</td><td>RBAC, Key Vault, Storage account policies, Defender for Cloud, NSG, Monitor</td></tr><tr><td>GCP</td><td>IAM, Cloud Audit Logs, VPC Service Controls, Security Command Center</td></tr></tbody></table><p>Coverage grows with each release. Controls without a matching module are listed in a <code>remediation-gaps.md</code> file so you know which findings still require manual work.</p><hr><h2 id="applying-the-modules" tabindex="-1">Applying the modules <a class="header-anchor" href="#applying-the-modules" aria-label="Permalink to &quot;Applying the modules&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/wsp/tf/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">timestam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terraform</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terraform</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plan</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">terraform</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div><p>Review the plan output carefully before applying. The generated modules use sensible defaults but your environment may have constraints -- naming conventions, tag requirements, or existing resources -- that require adjustment before apply.</p><hr><h2 id="re-running-after-apply" tabindex="-1">Re-running after apply <a class="header-anchor" href="#re-running-after-apply" aria-label="Permalink to &quot;Re-running after apply&quot;">​</a></h2><p>Once you have applied the generated modules, run the assessment again. Compliance controls that were previously GAP should now show SATISFIED if the Terraform configuration is correct and the environment has converged.</p><p>This close the loop between assessment findings and infrastructure remediation without manual tracking.</p><hr><div class="tip custom-block"><p class="custom-block-title">Enterprise feature</p><p>Module generation from LLM and Hybrid assessments, including generation from audit-derived findings, is an Enterprise edition feature.</p></div>`,22)])])}const g=t(n,[["render",r]]);export{c as __pageData,g as default};
